args.sparql:
SELECT ?athlete WHERE {
  wd:Q2658675 wdt:P1681 ?event.
  ?event rdfs:label ?label.
  FILTER (LANG(?label) = "en" && CONTAINS(STR(?label), "Men's singles figure skating"))
  ?event wdt:P431 ?athlete.
}

SELECT ?event WHERE {
  wd:Q2625024 wdt:P1545 ?event.
  ?event wdt:P1681 wd:Q2658675.
  ?event rdfs:label ?label.
  FILTER (lang(?label) = "en" && CONTAINS(STR(?label), "Men's singles"))
}

SELECT DISTINCT ?event WHERE {
  wd:Q2658675 wdt:P361 ?event;
  wdt:P136 wd:Q888.
  ?event rdfs:label ?label.
  FILTER (LANG(?label) = "en" && CONTAINS(STR(?label), "Men's singles"))
}

